import React from "react";
import { useParams } from "react-router-dom";
import {
  Container,
  Typography,
  Grid,
  Paper,
  Avatar,
  Divider,
  List,
  ListItem,
  ListItemText,
  Button,
} from "@mui/material";

// For now we search in hospitals array — later use proper data fetching
import { hospitals } from "../HospitalListing"; // adjust path

const DoctorProfile = () => {
  const { doctorId } = useParams();
  const idNum = Number(doctorId);

  // Find doctor across all hospitals
  let foundDoctor = null;
  for (const hospital of hospitals) {
    const doc = hospital.doctors?.find((d) => d.id === idNum);
    if (doc) {
      foundDoctor = { ...doc, hospitalName: hospital.name };
      break;
    }
  }

  if (!foundDoctor) {
    return (
      <Container sx={{ py: 8 }}>
        <Typography variant="h5" align="center">
          Doctor not found
        </Typography>
      </Container>
    );
  }

  return (
    <Container maxWidth="md" sx={{ py: 6 }}>
      <Paper elevation={4} sx={{ p: 4, borderRadius: 3 }}>
        <Grid container spacing={4}>
          <Grid item xs={12} md={4} sx={{ textAlign: "center" }}>
            <Avatar
              src={foundDoctor.image}
              alt={foundDoctor.name}
              sx={{ width: 200, height: 200, mx: "auto", mb: 2 }}
            />
            <Typography variant="h5" gutterBottom>
              {foundDoctor.name}
            </Typography>
            <Typography variant="subtitle1" color="primary">
              {foundDoctor.specialty}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {foundDoctor.hospitalName}
            </Typography>
          </Grid>

          <Grid item xs={12} md={8}>
            <Typography variant="h6" gutterBottom>
              Professional Details
            </Typography>
            <Divider sx={{ mb: 2 }} />

            <List>
              <ListItem>
                <ListItemText
                  primary="Experience"
                  secondary={foundDoctor.experience}
                />
              </ListItem>
              <ListItem>
                <ListItemText
                  primary="Qualification"
                  secondary={foundDoctor.qualification}
                />
              </ListItem>
              <ListItem>
                <ListItemText
                  primary="Availability"
                  secondary={foundDoctor.availability}
                />
              </ListItem>
              <ListItem>
                <ListItemText primary="Bio" secondary={foundDoctor.bio} />
              </ListItem>
            </List>

            <Box sx={{ mt: 4 }}>
              <Button variant="contained" color="primary" size="large">
                Book Appointment
              </Button>
            </Box>
          </Grid>
        </Grid>
      </Paper>
    </Container>
  );
};

export default DoctorProfile;
